// Compute ISO timestamp = 24h ago, format for Airtable filter
const since = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
return [{ json: { since, sinceDate: since.slice(0,10) } }];

// Aggregate stats + prepare GPT analysis payload.
const items = $input.all().map(i => i.json).filter(r => r && r.fields).map(r => r.fields);
const total = items.length;

if (total === 0) {
  return [{ json: { empty: true, total: 0 } }];
}

// Group by user
const byUser = {};
for (const r of items) {
  const u = r.TelegramUserId || 'unknown';
  byUser[u] = byUser[u] || { userId: u, count: 0, intents: {}, msgs: [] };
  byUser[u].count++;
  const it = r.Intent || 'unknown';
  byUser[u].intents[it] = (byUser[u].intents[it] || 0) + 1;
  byUser[u].msgs.push({
    ts: (r.Timestamp || '').slice(11, 19),
    intent: it,
    conf: r.Confidence || null,
    text: (r.MessageText || '').slice(0, 140),
    transcript: r.Transcript || '',
    bot: (r.ResultMessage || '').slice(0, 140),
  });
}

// Overall intent distribution
const intentsDist = {};
let confSum = 0, confN = 0;
for (const r of items) {
  const it = r.Intent || 'unknown';
  intentsDist[it] = (intentsDist[it] || 0) + 1;
  if (typeof r.Confidence === 'number') { confSum += r.Confidence; confN++; }
}
const avgConf = confN ? (confSum / confN) : null;

// Detect reformulations: same user, within 2 min, similar text length
const reformulations = [];
const sortedByUser = {};
for (const r of items) {
  const u = r.TelegramUserId || 'u';
  sortedByUser[u] = sortedByUser[u] || [];
  sortedByUser[u].push(r);
}
for (const u in sortedByUser) {
  const arr = sortedByUser[u].sort((a,b)=>new Date(a.Timestamp)-new Date(b.Timestamp));
  for (let i = 1; i < arr.length; i++) {
    const t1 = new Date(arr[i-1].Timestamp);
    const t2 = new Date(arr[i].Timestamp);
    const dtMin = (t2 - t1) / 60000;
    if (dtMin <= 2 && dtMin > 0) {
      // Consider it a likely reformulation
      reformulations.push({
        user: u,
        prev: { ts: arr[i-1].Timestamp, text: arr[i-1].MessageText, intent: arr[i-1].Intent },
        curr: { ts: arr[i].Timestamp, text: arr[i].MessageText, intent: arr[i].Intent },
      });
    }
  }
}

// Low confidence entries
const lowConf = items.filter(r => typeof r.Confidence === 'number' && r.Confidence < 0.7).map(r => ({
  ts: r.Timestamp,
  text: (r.MessageText || r.Transcript || '').slice(0, 140),
  intent: r.Intent,
  conf: r.Confidence,
}));

// Unknown intents
const unknowns = items.filter(r => r.Intent === 'unknown' || r.Intent === 'clarify').map(r => ({
  ts: r.Timestamp,
  text: (r.MessageText || r.Transcript || '').slice(0, 140),
  intent: r.Intent,
}));

const stats = {
  total,
  users: Object.keys(byUser).length,
  byUser: Object.values(byUser),
  intentsDist,
  avgConf: avgConf !== null ? Math.round(avgConf * 100) / 100 : null,
  reformulations: reformulations.slice(0, 15),
  lowConfCount: lowConf.length,
  lowConf: lowConf.slice(0, 10),
  unknownCount: unknowns.length,
  unknowns: unknowns.slice(0, 10),
};

return [{ json: { empty: false, stats } }];

// Build GPT analysis request.
const stats = $input.first().json.stats;

const systemPrompt = `Ты — аналитик, который разбирает логи Telegram-бота по стройке за прошедшие 24 часа и пишет краткую сводку для разработчика на русском языке.

Твоя задача:
1. Описать активность: сколько сообщений, от скольких пользователей, какие интенты преобладают.
2. Выявить ПРОБЛЕМЫ: переформулировки (=пользователь не получил ответ и переспросил), низкая уверенность GPT, unknown-интенты.
3. Предложить конкретные УЛУЧШЕНИЯ промпта или логики (паттерны, шаблоны фраз, новые интенты).

Тон: деловой, по существу, без воды. Фокус на actionable-советы.
Длина итогового отчёта: не больше 1500 символов (влезать в одно Telegram-сообщение).
Формат: Markdown с emoji для разделов.`;

const userContent = `Данные за последние 24 часа:\n\n${JSON.stringify(stats, null, 2)}\n\nСоставь краткую сводку для разработчика: активность, проблемы, предложения по улучшению.`;

const body = {
  model: 'gpt-5',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userContent }
  ]
};

return [{ json: { openaiBody: body, stats } }];

// Extract GPT summary text and compose final Telegram message.
const stats = $('Build Analysis Prompt').first().json.stats;
const gpt = $input.first().json;
let summary = '';
try { summary = gpt.choices[0].message.content || '(пусто)'; } catch(e) { summary = 'Ошибка парсинга ответа GPT'; }

const intentsLines = Object.entries(stats.intentsDist)
  .sort((a,b)=>b[1]-a[1])
  .map(([k,v]) => `  • ${k}: ${v}`)
  .join('
');

const header = `📊 *Сводка за прошедшие 24 часа*

• Сообщений: *${stats.total}*
• Пользователей: *${stats.users}*
• Средняя уверенность GPT: *${stats.avgConf !== null ? Math.round(stats.avgConf*100)+'%' : 'н/д'}*
• Переформулировок: *${stats.reformulations.length}*
• Низкая уверенность (<70%): *${stats.lowConfCount}*
• Unknown/clarify: *${stats.unknownCount}*

*Распределение интентов:*
${intentsLines}

━━━━━━━━━━━━━━━

${summary}`;

return [{ json: { chatId: '584268213', text: header } }];
